import React, { useEffect, useState } from "react";
import axios from "axios";

export default function ListaPeriodos({ onEditar, reloadKey }) {
  const [periodos, setPeriodos] = useState([]);
  const [carregando, setCarregando] = useState(true);

  useEffect(() => {
  setCarregando(true);
  axios
    .get("/api/periodos")
    .then((res) => {
      setPeriodos(res.data);
      setCarregando(false);
    })
    .catch(() => setCarregando(false));
}, [reloadKey]);

  const handleDeletar = (id) => {
    if (window.confirm("Tem certeza que deseja deletar este período?")) {
      axios
        .delete(`/api/periodos/${id}`)
        .then(() => setPeriodos(periodos.filter((p) => p.id !== id)));
    }
  };

  if (carregando) return <p>Carregando períodos...</p>;
  if (periodos.length === 0) return <p>Nenhum período cadastrado.</p>;

  return (
    <table className="min-w-full rounded-2xl shadow-sm bg-white mt-4">
  <thead>
    <tr className="border-b bg-gray-100">
      <th className="px-4 py-2 text-left text-[#1d3557] font-semibold">Nome</th>
      <th className="px-4 py-2 text-left text-[#1d3557] font-semibold">Turno</th>
      <th className="px-4 py-2"></th>
    </tr>
  </thead>
  <tbody>
    {periodos.map((p) => (
      <tr key={p.id} className="border-b last:border-0 hover:bg-gray-50 transition">
        <td className="px-4 py-3 font-medium text-gray-800">{p.nome}</td>
        <td className="px-4 py-3 text-gray-600">{p.turno}</td>
        <td className="px-4 py-3 flex gap-2">
          <button
            className="px-4 py-1 rounded-lg bg-blue-100 text-blue-800 hover:bg-blue-200 font-semibold transition"
            onClick={() => onEditar && onEditar(p)}
          >
            Editar
          </button>
          <button
            className="px-4 py-1 rounded-lg bg-red-100 text-red-700 hover:bg-red-200 font-semibold transition"
            onClick={() => handleDeletar(p.id)}
          >
            Deletar
          </button>
        </td>
      </tr>
    ))}
  </tbody>
</table>

  );
}
